INSERT INTO news (title, content, category, source, author_id) VALUES
  ('Патч 1.25: Новые карты и ребаланс', 'В обновлении 1.25 добавлены 2 новые карты — Горный перевал и Арктическая база. Проведён масштабный ребаланс тяжёлых танков VIII уровня. Улучшена физика движения по грязи и снегу.', 'patch', 'Мир Танков', 1),
  ('Турнир "Стальной кулак" — регистрация открыта', 'Открыта регистрация на клановый турнир. Призовой фонд — 50 000 голды. Участие могут принять все кланы с рейтингом от 1000. Регистрация до 30 апреля.', 'event', 'редакция', 1),
  ('Еженедельное обновление состава клана', 'По итогам недели 3 бойца повышены в звании. В роту Альфа приняты 2 новых игрока. Рота Браво временно закрыта для набора до конца месяца.', 'roster', 'редакция', 1),
  ('Ребаланс артиллерии в патче 1.26', 'В следующем патче 1.26 запланирован масштабный ребаланс артиллерийских САУ всех уровней. Урон снижен на 15%, точность улучшена.', 'patch', 'Мир Танков', 1),
  ('Клановые войны: сезон 24 стартовал', 'Новый сезон клановых войн начался. Наш клан занимает 12-е место в региональном рейтинге. Ежедневные бои в 21:00 МСК.', 'clan', 'редакция', 2);
